// tests/login.spec.js
const { test, expect } = require('@playwright/test');

test('standard user can log in', async ({ page }) => {
  await page.goto('https://www.saucedemo.com/');
  await page.getByPlaceholder('Username').fill('standard_user');
  await page.getByPlaceholder('Password').fill('secret_sauce');
  await page.getByRole('button', { name: 'Login' }).click();

  // Web-first assertion auto-waits until the URL matches
  await expect(page).toHaveURL(/inventory/);
  await expect(page.getByText('Products')).toBeVisible();
});
```

```javascript
const { test, expect } = require('@playwright/test');

test('checkout shows confirmation', async ({ page }) => {
  // ... perform checkout ...

  // Auto-retrying (web-first) hard assertions: wait until true or fail
  await expect(page).toHaveURL(/confirmation/);
  await expect(page.getByTestId('order-status')).toHaveText('Order confirmed');

  // Soft assertions: report ALL failures in one run
  await expect.soft(page.getByTestId('order-total')).toHaveText('$19.99');
  await expect.soft(page.getByTestId('stock-badge')).toHaveText('In stock');
});
```

